// In the future, separate services disambiguating the roles for a local and remote daemon
// may be wanted to avoid "directionality confusion". For example, we have
// a [GraftService.DiscoverCommands] RPC that gathers commands that could be forwarded
// to a client and this RPC can be sent to a local
// deamon (user->client->daemon(local)---network--->daemon(remote)) which is strange but
// also it's entirely possible for a local daemon to service a client as a remote
// daemon, albeit probably pointless.
//
// For now, we'll keep the service combined and you will notice many method that utilize
// presence/non-presenec of pids and connection names to distinguish where the command
// is intended to be processed.
type GraftServiceServer interface {
	// Status returns high-level information about the daemon (local/remote) such
	// as its health, version, and recent logs.
	Status(context.Context, *StatusRequest) (*StatusResponse, error)
	// Ping is a testing endpoint that prints messages to the OOB channel.
	Ping(context.Context, *PingRequest) (*PingResponse, error)
	// Shutdown requests that the daemon shuts down.
	Shutdown(context.Context, *ShutdownRequest) (*ShutdownResponse, error)
	// Restart requests that the daemon restarts.
	Restart(context.Context, *RestartRequest) (*RestartResponse, error)
	// OOBMessages subscribes to a broadcast stream of out-of-band messages that the daemon
	// can use to send clients information not strictly related to forwarded commands.
	// For instance, since the daemon handles initialization logic, it's helpful to provide
	// progress information while an RPC command is running instead of creating complicated
	// streaming protos that provide this information.
	//
	// TODO(erd): Evaluate if the correlation id concept is needed. It doesn't seem like it is
	// and the demuxing could be eliminated without it.
	OOBMessages(*OOBMessagesRequest, grpc.ServerStreamingServer[OOBMessagesResponse]) error
	// ListConnections lists all connections this daemon is responsible for.
	ListConnections(context.Context, *ListConnectionsRequest) (*ListConnectionsResponse, error)
	// InitializeSSHConnection initializes an SSH based connection.
	InitializeSSHConnection(context.Context, *InitializeSSHConnectionRequest) (*InitializeSSHConnectionResponse, error)
	// InitializeContainerConnection initializations a docker based connection.
	InitializeContainerConnection(context.Context, *InitializeContainerConnectionRequest) (*InitializeContainerConnectionResponse, error)
	// RemoveConnection tears down the specified connection.
	RemoveConnection(context.Context, *RemoveConnectionRequest) (*RemoveConnectionResponse, error)
	// DiscoverCommands streams all commands a daemon thinks it can allow a client to forward.
	DiscoverCommands(*DiscoverCommandsRequest, grpc.ServerStreamingServer[DiscoverCommandsResponse]) error
	// UpdateConnectionRoots updates the local and/or remote root directories for a connection.
	UpdateConnectionRoots(context.Context, *UpdateConnectionRootsRequest) (*UpdateConnectionRootsResponse, error)
	// UpdateConnectionForwardCommands adds the specified commands to be forwarded for a connection.
	//
	// TODO(erd): should this be replace or insert?
	UpdateConnectionForwardCommands(context.Context, *UpdateConnectionForwardCommandsRequest) (*UpdateConnectionForwardCommandsResponse, error)
	// RemoveConnectionForwardCommands removes the specified commands from being forwarded for a connection.
	RemoveConnectionForwardCommands(context.Context, *RemoveConnectionForwardCommandsRequest) (*RemoveConnectionForwardCommandsResponse, error)
	// SyncFilesToConnection sets up a bidirectional synchronization between the local and remote daemons.
	SyncFilesToConnection(context.Context, *SyncFilesToConnectionRequest) (*SyncFilesToConnectionResponse, error)
	// DumpLogs dumps all found daemon logs as raw text.
	DumpLogs(context.Context, *DumpLogsRequest) (*DumpLogsResponse, error)
	// SyncFilesToConnectionProtocol is used for the underlying mutagen sync protocol that bypasses
	// the mutagen daemon installation process. We do this bypass because:
	// - we were curious how easy it was to do this given mutagen/graft are both written in go
	// - it affords us one installation, making updates and maintenance a lot easier
	// - allows us to move away from mutagen if needed
	//
	// The protocol is binary/opaque to us. It's a protobuf based protocol but not gRPC. We could actually
	// implement the idea of local/remote endpoints but it's a lot easier to just pass it through for now.
	SyncFilesToConnectionProtocol(grpc.BidiStreamingServer[SyncFilesToConnectionProtocolRequest, SyncFilesToConnectionProtocolResponse]) error
	// TODO(erd): Consider integrating ForwardSSHAgent into connection initialization.
	ForwardSSHAgent(grpc.BidiStreamingServer[ForwardSSHAgentRequest, ForwardSSHAgentResponse]) error
	// WatchPorts is a server-streaming RPC called by the local daemon against the remote daemon.
	// The remote daemon pushes a full snapshot of listening ports whenever the set changes.
	WatchPorts(*WatchPortsRequest, grpc.ServerStreamingServer[WatchPortsResponse]) error
	// ForwardPort is a bidirectional streaming RPC for relaying a single TCP connection or UDP
	// session between local and remote. The first ForwardPortRequest must contain a ForwardPortStart
	// message identifying the target; subsequent messages carry raw payload bytes.
	ForwardPort(grpc.BidiStreamingServer[ForwardPortRequest, ForwardPortResponse]) error
	// AddPortForwards adds explicit port forwards to a connection. Explicit port forwards
	// are not affected by auto-detection lifecycle; they persist until explicitly removed.
	AddPortForwards(context.Context, *AddPortForwardsRequest) (*AddPortForwardsResponse, error)
	// RemovePortForwards removes explicit port forwards from a connection.
	RemovePortForwards(context.Context, *RemovePortForwardsRequest) (*RemovePortForwardsResponse, error)
	// SessionReportCWD informs the daemon of a session's current working directory so that it can be mirrored on the remote.
	SessionReportCWD(context.Context, *SessionReportCWDRequest) (*SessionReportCWDResponse, error)
	// SessionWhich asks which connection can handle the given command.
	SessionWhich(context.Context, *SessionWhichRequest) (*SessionWhichResponse, error)
	// SessionShimmedCommands returns all commands that should be shimmed for a session across all established connections.
	SessionShimmedCommands(context.Context, *SessionShimmedCommandsRequest) (*SessionShimmedCommandsResponse, error)
	// SessionSelectConnection returns the best connection for session.
	SessionSelectConnection(context.Context, *SessionSelectConnectionRequest) (*SessionSelectConnectionResponse, error)
	// SessionPinConnection pins a connection to a session, overriding CWD-based auto-selection.
	SessionPinConnection(context.Context, *SessionPinConnectionRequest) (*SessionPinConnectionResponse, error)
	// RunCommand runs the given command on the daemon (locally or forwarded to remote) and exposes std[in/out/err] streams to use.
	//
	// Additionally, the client can control tty information like terminal resizing.
	RunCommand(grpc.BidiStreamingServer[RunCommandRequest, RunCommandResponse]) error
	mustEmbedUnimplementedGraftServiceServer()
}

